+func TestDependencyFilteringInAssignment(t *testing.T) {
+	// Test the SkippedItem structure has correct fields
+	skipped := SkippedItem{
+		BeadID:       "bd-123",
+		BeadTitle:    "Test blocked bead",
+		Reason:       "blocked_by_dependency",
