+// TestIsBeadInCycle tests the cycle detection helper function
+func TestIsBeadInCycle(t *testing.T) {
+	cycles := [][]string{
+		{"bd-001", "bd-002", "bd-003"},
+		{"bd-010", "bd-011"},
+	}
+
+	tests := []struct {
+		name     string
